#!/usr/bin/perl

use strict;
use warnings;
use CGI;

my $cgi = CGI->new();
print $cgi->header('text/html');

my $comment = $cgi->param('comment') || '';

# Sanitize input to allow basic HTML only
$comment =~ s/<script.*?>.*?<\/script>//gi; # remove script tags
$comment =~ s/<\/?[^>]+>//g; # remove all other tags (only allow text)

print "<div>$comment</div>";